# ─── FETCH LIVE PRICES ───────────────────────────────────────────────────────
@st.cache_data(ttl=300)  # cache 5 minutes
def fetch_live_prices(symbols):
    prices = {}
    BATCH = 50
    for i in range(0, len(symbols), BATCH):
        batch = symbols[i:i+BATCH]
        tickers = [s + ".NS" for s in batch]
        try:
            raw = yf.download(
                tickers, period="1d", interval="1d",
                auto_adjust=True, progress=False, threads=True
            )
            if raw.empty:
                continue
            if isinstance(raw.columns, pd.MultiIndex):
                closes = raw["Close"].iloc[-1]
            else:
                closes = raw.iloc[-1]
            for sym in batch:
                t = sym + ".NS"
                try:
                    val = closes.get(t) if hasattr(closes, "get") else closes[t]
                    if val is not None and not np.isnan(float(val)):
                        prices[sym] = round(float(val), 2)
                except:
                    pass
        except:
            pass
        time.sleep(0.2)
    return prices

# ─── FILTER CANDIDATES FIRST ─────────────────────────────────────────────────
candidates = [
    s for s in STOCK_DATA
    if s["score"] >= min_score
    and s["rr"] >= min_rr
    and s["tier"] in tiers
    and (not above200_only or s["above_200"])
]

symbols_to_fetch = [s["sym"] for s in candidates]

with st.spinner(f"Fetching live prices for {len(symbols_to_fetch)} stocks..."):
    live = fetch_live_prices(symbols_to_fetch)

st.success(f"✓ Live prices loaded — {datetime.now().strftime('%H:%M:%S')} IST")

# ─── COMPUTE DISTANCES ───────────────────────────────────────────────────────
rows = []
for s in candidates:
    sym = s["sym"]
    if sym not in live:
        continue
    price = live[sym]
    crash_buy = s["crash_buy"]
    dist_pct = (price / crash_buy - 1) * 100

    # L2 and L3 tranche levels
    l2 = crash_buy * (1 - s["avg_drop"] * 0.15 / 100)
    l3 = crash_buy * (1 - s["avg_drop"] * 0.30 / 100)
    sl = l3 * 0.95

    rows.append({
        **s,
        "live": price,
        "dist_pct": round(dist_pct, 2),
        "l2": round(l2, 2),
        "l3": round(l3, 2),
        "sl": round(sl, 2),
        "upside_pct": round((s["rot_target"] / price - 1) * 100, 1),
    })

rows.sort(key=lambda x: x["dist_pct"])

in_zone    = [r for r in rows if r["dist_pct"] <= 0]
near_zone  = [r for r in rows if 0 < r["dist_pct"] <= prox]

# ─── SUMMARY METRICS ─────────────────────────────────────────────────────────
c1, c2, c3 = st.columns(3)
c1.metric("🟢 In Buy Zone",    len(in_zone))
c2.metric("🟡 Approaching",    len(near_zone))
c3.metric("📊 Scanned",        len(rows))

st.divider()

# ─── RENDER CARDS ────────────────────────────────────────────────────────────
def render_card(r):
    dist = r["dist_pct"]
    if dist <= 0:
        css = "card-green"
        dist_color = "green"
        icon = "🟢"
    elif dist <= 5:
        css = "card-yellow"
        dist_color = "yellow"
        icon = "🟡"
    else:
        css = "card"
        dist_color = "yellow"
        icon = "⏳"

    sign = "+" if dist > 0 else ""
    above = "↑200DMA" if r["above_200"] else "↓200DMA"
    days_est = int(r.get("drop_days", 20))

    st.markdown(f"""
    <div class="card {css}">
      <div>
        <span class="sym">{icon} {r["sym"]}</span>
        <span class="tier">{r["tier"]}</span>
        <span class="tier" style="background:#1a2a40;color:#94a3b8">{above}</span>
      </div>
      <div class="dist {dist_color}">{sign}{dist:.2f}% to zone</div>
      <div class="meta">Score {r["score"]} · R:R {r["rr"]} · Win {int(r["win_pct"])}% · {r["rot_yr"]}×/yr</div>
      <div class="price-row">
        <div>
          <div class="price-label">LIVE PRICE</div>
          <div class="price-val">₹{r["live"]:,.2f}</div>
        </div>
        <div>
          <div class="price-label">CRASH BUY (L1)</div>
          <div class="price-val">₹{r["crash_buy"]:,.2f}</div>
        </div>
        <div>
          <div class="price-label">TARGET</div>
          <div class="price-val" style="color:#22c55e">₹{r["rot_target"]:,.2f}</div>
        </div>
        <div>
          <div class="price-label">UPSIDE</div>
          <div class="price-val" style="color:#22c55e">+{r["upside_pct"]}%</div>
        </div>
      </div>
      <div class="price-row" style="margin-top:6px">
        <div>
          <div class="price-label">L2 (35%)</div>
          <div class="price-val" style="font-size:0.8rem">₹{r["l2"]:,.2f}</div>
        </div>
        <div>
          <div class="price-label">L3 (25%)</div>
          <div class="price-val" style="font-size:0.8rem">₹{r["l3"]:,.2f}</div>
        </div>
        <div>
          <div class="price-label">HARD SL</div>
          <div class="price-val" style="font-size:0.8rem;color:#ef4444">₹{r["sl"]:,.2f}</div>
        </div>
        <div>
          <div class="price-label">AVG DAYS</div>
          <div class="price-val" style="font-size:0.8rem">~{days_est}d</div>
        </div>
      </div>
    </div>
    """, unsafe_allow_html=True)

# IN ZONE
if in_zone:
    st.markdown(f"### 🟢 In Buy Zone ({len(in_zone)})")
    st.caption("GTC should already be set — verify orders are active")
    for r in in_zone[:20]:
        render_card(r)
else:
    st.info("No stocks in buy zone right now.")

# APPROACHING
if near_zone:
    st.markdown(f"### 🟡 Approaching — within {prox}% ({len(near_zone)})")
    st.caption("Set GTC orders for these now")
    for r in near_zone[:25]:
        render_card(r)

